      buttonDangerFocusedPressed: Color.lerp(buttonDangerFocusedPressed, other.buttonDangerFocusedPressed, t)!,
      buttonDangerHovered: Color.lerp(buttonDangerHovered, other.buttonDangerHovered, t)!,
      buttonGhostDisabled: Color.lerp(buttonGhostDisabled, other.buttonGhostDisabled, t)!,
      buttonGhostHovered: Color.lerp(buttonGhostHovered, other.buttonGhostHovered, t)!,
      buttonGhostPressed: Color.lerp(buttonGhostPressed, other.buttonGhostPressed, t)!,
      buttonGhostWhiteFixedDisabled: Color.lerp(buttonGhostWhiteFixedDisabled, other.buttonGhostWhiteFixedDisabled, t)!,
      buttonGhostWhiteFixedHovered: Color.lerp(buttonGhostWhiteFixedHovered, other.buttonGhostWhiteFixedHovered, t)!,
      buttonGhostWhiteFixedPressed: Color.lerp(buttonGhostWhiteFixedPressed, other.buttonGhostWhiteFixedPressed, t)!,
      buttonInverse: Color.lerp(buttonInverse, other.buttonInverse, t)!,
